#include <stdio.h>
#include <stdlib.h>

int main() {
    int n; 
    scanf("%d", &n);

    int *supw = (int *)malloc(n * sizeof(int));
    int *dp = (int *)malloc(n * sizeof(int));

    for (int i = 0; i < n; i++) {
        scanf("%d", &supw[i]);
        dp[i] = supw[i];
    }

    for (int i = n - 4; i >= 0; i--) {
        dp[i] += (dp[i + 1] < dp[i + 2] ? 
                   (dp[i + 1] < dp[i + 3] ? dp[i + 1] : dp[i + 3]) : 
                   (dp[i + 2] < dp[i + 3] ? dp[i + 2] : dp[i + 3]));
    }

    int result = dp[0] < dp[1] ? (dp[0] < dp[2] ? dp[0] : dp[2]) : (dp[1] < dp[2] ? dp[1] : dp[2]);
    printf("%d\n", result);

    // Free allocated memory
    free(supw);
    free(dp);

    return 0;
}

