import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef
{
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        // Read the number of elements
        int n = scanner.nextInt();
        int[] supw = new int[n];
        int[] dp = new int[n];

        // Read the elements into supw and initialize dp
        for (int i = 0; i < n; i++) {
            supw[i] = scanner.nextInt();
            dp[i] = supw[i];
        }

        // Dynamic programming to calculate minimum path sums
        for (int i = n - 4; i >= 0; i--) {
            dp[i] += Math.min(dp[i + 1], Math.min(dp[i + 2], dp[i + 3]));
        }

        // Output the minimum value from dp[0], dp[1], and dp[2]
        System.out.println(Math.min(dp[0], Math.min(dp[1], dp[2])));

        // Close the scanner
        scanner.close();
    }
}

