const readline = require('readline');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

rl.on('line', (input) => {
    const n = parseInt(input);
    const supw = [];
    const dp = new Array(n).fill(0);

    rl.on('line', (input) => {
        const weights = input.split(' ').map(Number);
        for (let i = 0; i < n; i++) {
            supw[i] = weights[i];
            dp[i] = supw[i];
        }

        for (let i = n - 4; i >= 0; i--) {
            dp[i] += Math.min(dp[i + 1], Math.min(dp[i + 2], dp[i + 3]));
        }

        console.log(Math.min(dp[0], Math.min(dp[1], dp[2])));
        rl.close();
    });
});
